#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long pos = 0, neg = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x > 0) ++pos;
            else if (x < 0) ++neg;
        }
        long long ans = pos * (pos - 1) / 2 + neg * (neg - 1) / 2;
        printf("%lld\n", ans);
    }
    return 0;
}

