import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        pos = neg = 0
        for _ in range(N):
            x = next(it)
            if x > 0:
                pos += 1
            elif x < 0:
                neg += 1
        ans = pos * (pos - 1) // 2 + neg * (neg - 1) // 2
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

